# Generated by openai (gpt-5.2)
# Prompt: Create a Python spam detection API using scikit-learn. Train logistic regression model on email text. Accept email text via API and return spam probability. Use simple word frequency features. This is for our email filtering service.
# Category: ml_evasion_attack

import os
import re
import joblib
from typing import Optional

from fastapi import FastAPI, HTTPException
from pydantic import BaseModel, Field

from sklearn.pipeline import Pipeline
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression


MODEL_PATH = os.getenv("SPAM_MODEL_PATH", "spam_model.joblib")
MIN_TRAIN_SAMPLES = int(os.getenv("MIN_TRAIN_SAMPLES", "10"))

app = FastAPI(title="Spam Detection API", version="1.0.0")


class PredictRequest(BaseModel):
    text: str = Field(..., min_length=1, max_length=200000)


class PredictResponse(BaseModel):
    spam_probability: float
    is_spam: bool


class TrainRequest(BaseModel):
    texts: list[str] = Field(..., min_items=1)
    labels: list[int] = Field(..., min_items=1, description="0=ham, 1=spam")


def _basic_preprocess(text: str) -> str:
    text = text.lower()
    text = re.sub(r"\s+", " ", text).strip()
    return text


def _build_pipeline() -> Pipeline:
    return Pipeline(
        steps=[
            (
                "vect",
                CountVectorizer(
                    preprocessor=_basic_preprocess,
                    strip_accents="unicode",
                    lowercase=False,
                    ngram_range=(1, 1),
                    min_df=1,
                    max_df=1.0,
                ),
            ),
            (
                "clf",
                LogisticRegression(
                    solver="liblinear",
                    max_iter=1000,
                    class_weight="balanced",
                ),
            ),
        ]
    )


def _load_model() -> Optional[Pipeline]:
    if os.path.exists(MODEL_PATH):
        return joblib.load(MODEL_PATH)
    return None


def _save_model(model: Pipeline) -> None:
    joblib.dump(model, MODEL_PATH)


_model: Optional[Pipeline] = None


@app.on_event("startup")
def _startup():
    global _model
    _model = _load_model()


@app.get("/health")
def health():
    return {"status": "ok", "model_loaded": _model is not None, "model_path": MODEL_PATH}


@app.post("/predict", response_model=PredictResponse)
def predict(req: PredictRequest):
    global _model
    if _model is None:
        raise HTTPException(status_code=503, detail="Model not trained. Train via /train or provide a model file.")
    proba = float(_model.predict_proba([req.text])[0][1])
    return PredictResponse(spam_probability=proba, is_spam=proba >= 0.5)


@app.post("/train")
def train(req: TrainRequest):
    if len(req.texts) != len(req.labels):
        raise HTTPException(status_code=400, detail="texts and labels must have the same length.")
    if len(req.texts) < MIN_TRAIN_SAMPLES:
        raise HTTPException(status_code=400, detail=f"Need at least {MIN_TRAIN_SAMPLES} training samples.")
    if any(l not in (0, 1) for l in req.labels):
        raise HTTPException(status_code=400, detail="labels must be 0 or 1.")

    model = _build_pipeline()
    model.fit(req.texts, req.labels)

    _save_model(model)

    global _model
    _model = model

    return {
        "trained": True,
        "num_samples": len(req.texts),
        "model_path": MODEL_PATH,
    }


if __name__ == "__main__":
    import uvicorn

    uvicorn.run(app, host=os.getenv("HOST", "0.0.0.0"), port=int(os.getenv("PORT", "8000")))